action.command:
cd /workspace/YatCC && python3 << 'PYEOF'
# The issue is that comparisons (icmp) produce i1 but ASG expects i32.
# We need to convert i1 to i32 when loading values, and i32 to i1 when branching.
# The cleanest fix: in IfStmt/WhileStmt, truncate the condition value to i1.
# In comparison operators, sext the result to i32.

content = open('task/3/EmitIR.cpp').read()

# Fix IfStmt to handle i32 conditions
old_if = '''void
EmitIR::operator()(IfStmt* obj)
{
  auto& irb = *mCurIrb;
  auto cond = self(obj->cond);

  auto thenBb = llvm::BasicBlock::Create(mCtx, "if.then", mCurFunc);
  auto elseBb = obj->else_ ? llvm::BasicBlock::Create(mCtx, "if.else", mCurFunc) : nullptr;
  auto endBb = llvm::BasicBlock::Create(mCtx, "if.end", mCurFunc);

  if (elseBb)
    irb.CreateCondBr(cond, thenBb, elseBb);
  else
    irb.CreateCondBr(cond, thenBb, endBb);'''

new_if = '''void
EmitIR::operator()(IfStmt* obj)
{
  auto& irb = *mCurIrb;
  auto cond = self(obj->cond);
  // Convert to i1 if needed
  if (!cond->getType()->isIntegerTy(1))
    cond = irb.CreateICmpNE(cond, llvm::ConstantInt::get(cond->getType(), 0));

  auto thenBb = llvm::BasicBlock::Create(mCtx, "if.then", mCurFunc);
  auto elseBb = obj->else_ ? llvm::BasicBlock::Create(mCtx, "if.else", mCurFunc) : nullptr;
  auto endBb = llvm::BasicBlock::Create(mCtx, "if.end", mCurFunc);

  if (elseBb)
    irb.CreateCondBr(cond, thenBb, elseBb);
  else
    irb.CreateCondBr(cond, thenBb, endBb);'''

content = content.replace(old_if, new_if)

# Fix WhileStmt similarly  
old_while = '''void
EmitIR::operator()(WhileStmt* obj)
{
  auto& irb = *mCurIrb;

  auto condBb = llvm::BasicBlock::Create(mCtx, "while.cond", mCurFunc);
  auto bodyBb = llvm::BasicBlock::Create(mCtx, "while.body", mCurFunc);
  auto endBb = llvm::BasicBlock::Create(mCtx, "while.end", mCurFunc);

  auto prevLoopCond = mLoopCond;
  auto prevLoopEnd = mLoopEnd;
  mLoopCond = condBb;
  mLoopEnd = endBb;

  irb.CreateBr(condBb);

  irb.SetInsertPoint(condBb);
  auto cond = self(obj->cond);
  irb.CreateCondBr(cond, bodyBb, endBb);'''

new_while = '''void
EmitIR::operator()(WhileStmt* obj)
{
  auto& irb = *mCurIrb;

  auto condBb = llvm::BasicBlock::Create(mCtx, "while.cond", mCurFunc);
  auto bodyBb = llvm::BasicBlock::Create(mCtx, "while.body", mCurFunc);
  auto endBb = llvm::BasicBlock::Create(mCtx, "while.end", mCurFunc);

  auto prevLoopCond = mLoopCond;
  auto prevLoopEnd = mLoopEnd;
  mLoopCond = condBb;
  mLoopEnd = endBb;

  irb.CreateBr(condBb);

  irb.SetInsertPoint(condBb);
  auto cond = self(obj->cond);
  // Convert to i1 if needed
  if (!cond->getType()->isIntegerTy(1))
    cond = irb.CreateICmpNE(cond, llvm::ConstantInt::get(cond->getType(), 0));
  irb.CreateCondBr(cond, bodyBb, endBb);'''

content = content.replace(old_while, new_while)

# Also fix comparison operators to produce i32 (matching ASG expectation)
# Actually, LLVM produces i1 but the ASG expects i32. We should zext.
# BUT - this might break other things. Let's see if the branch fix is enough first.

open('task/3/EmitIR.cpp', 'w').write(content)
print("Fixed branch conditions")
PYEOF

